import type { ContractArtifact } from '@aztec/aztec.js/abi';
import type { ContractBase } from '@aztec/aztec.js/contracts';
import type { ContractFunctionInteraction } from '@aztec/aztec.js/contracts';
import type { FeePaymentMethodType } from '../config/feePaymentContracts';

/**
 * Extract method names from a contract class.
 * Works with autogenerated Aztec contract classes.
 *
 * @example
 * type DripperMethods = MethodsOf<DripperContract>;
 * // = 'drip_to_private' | 'drip_to_public' | ...
 */
export type MethodsOf<TContract> = TContract extends { methods: infer M }
  ? keyof M
  : never;

/**
 * Extract the argument types for a specific method of a contract.
 *
 * @example
 * type Args = ArgsOf<DripperContract, 'drip_to_private'>;
 * // = [AztecAddressLike, bigint | number]
 */
export type ArgsOf<
  TContract,
  TMethod extends MethodsOf<TContract>,
> = TContract extends {
  methods: {
    [K in TMethod]: (...args: infer A) => ContractFunctionInteraction;
  };
}
  ? A
  : never;

/**
 * Type helper to extract contract type from a contract class.
 * Uses the static `at` method signature to infer the contract instance type.
 */
export type ContractClassFor<TContract extends ContractBase> = {
  artifact: ContractArtifact;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  at: (...args: any[]) => Promise<TContract> | TContract;
};

// =============================================================================
// Shared TanStack Query/Mutation option types
// =============================================================================

/** TanStack Query options passthrough for read hooks. */
export interface ContractQueryOptions<TSelectData = unknown> {
  /** Additional gate to enable/disable the query (default: true) */
  enabled?: boolean;
  /** Time in ms before data is considered stale */
  staleTime?: number;
  /** Time in ms before inactive query data is garbage collected */
  gcTime?: number;
  /** Polling interval in ms, or false to disable */
  refetchInterval?: number | false;
  /** Whether to refetch on window focus */
  refetchOnWindowFocus?: boolean;
  /** Transform the raw result before returning */
  select?: (data: unknown) => TSelectData;
  /** Retry count or boolean */
  retry?: number | boolean;
}

/** TanStack Mutation options passthrough for write hooks. */
export interface ContractMutationOptions {
  /** Called on successful write */
  onSuccess?: (data: WriteContractData) => void;
  /** Called on write failure */
  onError?: (error: Error) => void;
  /** Called when mutation settles (success or error) */
  onSettled?: (
    data: WriteContractData | undefined,
    error: Error | null
  ) => void;
}

// =============================================================================
// useReadContract types
// =============================================================================

/**
 * Parameters for the declarative useReadContract hook.
 * Mirrors wagmi's useReadContract API with Aztec-specific extensions.
 */
export interface UseReadContractParams<
  TContract extends ContractBase,
  TMethod extends MethodsOf<TContract>,
  TSelectData = unknown,
> {
  /** TanStack Query key — used for caching and invalidation. Auto-generated from contract params when omitted. */
  queryKey?: readonly unknown[];
  /** Contract class — used for type inference and artifact */
  contract: ContractClassFor<TContract>;
  /** Contract address. Set to undefined to auto-disable the query. */
  address: string | undefined;
  /** Method name to simulate */
  functionName: TMethod;
  /** Method arguments. Set to undefined to auto-disable the query. */
  args: ArgsOf<TContract, TMethod> | undefined;
  /** TanStack Query options (enabled, staleTime, gcTime, etc.) */
  query?: ContractQueryOptions<TSelectData>;
}

/**
 * Return type for the declarative useReadContract hook.
 */
export interface UseReadContractReturn<TData = unknown> {
  data: TData | undefined;
  error: Error | null;
  /** True during first load when no cached data exists */
  isLoading: boolean;
  /** True while the query hasn't resolved yet */
  isPending: boolean;
  isSuccess: boolean;
  isError: boolean;
  /** True during any background fetch (including refetches) */
  isFetching: boolean;
  status: 'pending' | 'error' | 'success';
  refetch: () => Promise<void>;
}

// =============================================================================
// useWriteContract types
// =============================================================================

/**
 * Data returned from a successful write operation.
 */
export interface WriteContractData {
  txHash?: string;
  result?: unknown;
}

/**
 * Parameters passed per-call to writeContract / writeContractAsync.
 */
export interface WriteContractMutateParams<
  TContract extends ContractBase,
  TMethod extends MethodsOf<TContract>,
> {
  /** Contract class — used for type inference and artifact */
  contract: ContractClassFor<TContract>;
  /** Contract address */
  address: string;
  /** Method name to call */
  functionName: TMethod;
  /** Method arguments */
  args: ArgsOf<TContract, TMethod>;
  /** Fee payment method (Aztec-specific, defaults to store value) */
  feePaymentMethod?: FeePaymentMethodType;
}

/**
 * Options for the useWriteContract hook.
 */
export interface UseWriteContractOptions {
  /** Timeout for transaction confirmation in ms (default: 900) */
  timeout?: number;
  /** Receipt polling options for browser wallet */
  receiptPolling?: { intervalMs?: number; maxAttempts?: number };
  /** TanStack Mutation options (onSuccess, onError, onSettled) */
  mutation?: ContractMutationOptions;
}

/**
 * Return type for the useWriteContract hook.
 */
export interface UseWriteContractReturn {
  /** Fire-and-forget write (errors go to isError/error) */
  writeContract: <T extends ContractBase, M extends MethodsOf<T>>(
    params: WriteContractMutateParams<T, M>
  ) => void;
  /** Async write that returns the result or throws */
  writeContractAsync: <T extends ContractBase, M extends MethodsOf<T>>(
    params: WriteContractMutateParams<T, M>
  ) => Promise<WriteContractData>;
  data: WriteContractData | undefined;
  error: Error | null;
  isPending: boolean;
  isSuccess: boolean;
  isError: boolean;
  isIdle: boolean;
  status: 'idle' | 'pending' | 'error' | 'success';
  reset: () => void;
}

// =============================================================================
// useReadContracts types (batch reads)
// =============================================================================

/** A single contract read config within a batch (one entry in the contracts array). */
export interface ReadContractsContract<
  TContract extends ContractBase = ContractBase,
  TMethod extends MethodsOf<TContract> = MethodsOf<TContract>,
> {
  contract: ContractClassFor<TContract>;
  address: string;
  functionName: TMethod;
  args: ArgsOf<TContract, TMethod>;
}

/** Per-result shape when allowFailure is true. Discriminated union on `status`. */
export type ReadContractResult =
  | { status: 'success'; result: unknown; error?: undefined }
  | { status: 'failure'; result?: undefined; error: Error };

/** Params for useReadContracts. */
export interface UseReadContractsParams<
  TAllowFailure extends boolean = true,
  TSelectData = TAllowFailure extends true ? ReadContractResult[] : unknown[],
> {
  /** TanStack Query key — used for caching and invalidation. Auto-generated from contracts array when omitted. */
  queryKey?: readonly unknown[];
  contracts: ReadContractsContract[];
  allowFailure?: TAllowFailure;
  /** TanStack Query options (enabled, staleTime, gcTime, etc.) */
  query?: ContractQueryOptions<TSelectData>;
}

/** Return type for useReadContracts. Same shape as useReadContract. */
export interface UseReadContractsReturn<TData = ReadContractResult[]> {
  data: TData | undefined;
  error: Error | null;
  isLoading: boolean;
  isPending: boolean;
  isSuccess: boolean;
  isError: boolean;
  isFetching: boolean;
  status: 'pending' | 'error' | 'success';
  refetch: () => Promise<void>;
}

// =============================================================================
// Dynamic contract types
// =============================================================================

/**
 * Configuration for a dynamic (untyped) contract read/simulate operation.
 * Used when only a raw artifact is available (e.g. Contract Explorer).
 */
export interface DynamicReadContractConfig {
  artifact: ContractArtifact;
  address: string;
  functionName: string;
  args: unknown[];
}

/**
 * Configuration for a dynamic (untyped) contract write operation.
 * Used when only a raw artifact is available (e.g. Contract Explorer).
 */
export interface DynamicWriteContractConfig {
  artifact: ContractArtifact;
  address: string;
  functionName: string;
  args: unknown[];
}
